                upperDiagonal[n - 1 + col - row] = 1;

                // Recurse
                solve(col + 1, board, n, leftRow, upperDiagonal, lowerDiagonal, res);

                // Backtrack
                board[row][col] = '.';
                leftRow[row] = 0;
                lowerDiagonal[row + col] = 0;
                upperDiagonal[n - 1 + col - row] = 0;
            }
        }
    }

    // Main function
